import React from 'react';
import {
  MemoryRouter as Router,
  Routes,
  Route,
  Navigate,
} from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from '@linm-soft-org/linm-web-common-components';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';
import { MemoryRouterSync } from './router/MemoryRouterSync';

const DevPage = React.lazy(() => import('./dev/DevPage'));

// ── Nhân Sự (ns) ──────────────────────────────────────────────────────────
const NhanVienListPage  = React.lazy(() => import('./pages/ns/NhanVienListPage'));
const NhanVienFormPage  = React.lazy(() => import('./pages/ns/NhanVienFormPage'));
const ChamCongPage      = React.lazy(() => import('./pages/ns/ChamCongPage'));
const CaLamViecPage     = React.lazy(() => import('./pages/ns/CaLamViecPage'));
const NhomNhanVienPage  = React.lazy(() => import('./pages/ns/NhomNhanVienPage'));
const BangLuongPage     = React.lazy(() => import('./pages/ns/BangLuongPage'));
const SoLuongKhoanPage  = React.lazy(() => import('./pages/ns/SoLuongKhoanPage'));
const BhxhReportPage    = React.lazy(() => import('./pages/ns/BhxhReportPage'));
const BaoCaoDiTrePage   = React.lazy(() => import('./pages/ns/BaoCaoDiTrePage'));
const BaoCaoCongPage    = React.lazy(() => import('./pages/ns/BaoCaoCongPage'));

const Suspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div style={{ padding: '2rem' }}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);

const AppShell: React.FC = () => (
  <>
    {isStandalone && <StandaloneMockNav />}
    <AppLayout />
  </>
);

const initialPath =
  typeof window !== 'undefined'
    ? window.location.pathname + window.location.search || '/'
    : '/';

const Root: React.FC = () => (
  <Provider store={store}>
    <Router initialEntries={[initialPath]} initialIndex={0}>
      <MemoryRouterSync />
      <Routes>
        <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>
          {showDevNav && (
            <>
              <Route index element={<Navigate to="/dev" replace />} />
              <Route path="dev" element={<Suspense><DevPage /></Suspense>} />
            </>
          )}
          <Route path="ns" element={<Navigate to="ns/nhan-vien" replace />} />
          <Route path="ns/nhan-vien"      element={<Suspense><NhanVienListPage /></Suspense>} />
          <Route path="ns/nhan-vien/them" element={<Suspense><NhanVienFormPage /></Suspense>} />
          <Route path="ns/nhan-vien/:id"  element={<Suspense><NhanVienFormPage /></Suspense>} />
          <Route path="ns/cham-cong"      element={<Suspense><ChamCongPage /></Suspense>} />
          <Route path="ns/ca-lam-viec"    element={<Suspense><CaLamViecPage /></Suspense>} />
          <Route path="ns/nhom-nhan-vien" element={<Suspense><NhomNhanVienPage /></Suspense>} />
          <Route path="ns/bang-luong"     element={<Suspense><BangLuongPage /></Suspense>} />
          <Route path="ns/so-luong-khoan" element={<Suspense><SoLuongKhoanPage /></Suspense>} />
          <Route path="ns/bhxh"           element={<Suspense><BhxhReportPage /></Suspense>} />
          <Route path="ns/bao-cao-di-tre" element={<Suspense><BaoCaoDiTrePage /></Suspense>} />
          <Route path="ns/bao-cao-cong"   element={<Suspense><BaoCaoCongPage /></Suspense>} />
          <Route path="*" element={<SimpleNotFoundPage showDevNav={showDevNav} homePath="/ns/nhan-vien" />} />
        </Route>
      </Routes>
    </Router>
  </Provider>
);

export default Root;
